  // related. Track pairs, rather than each object independently, so a value
  // being seen on one side does not make a later comparison equal by itself.
  // Seeing the same pair again is the case that can only be caused by a
  // circular reference, and can safely terminate that branch.
  let comparedWith = visited.get(object1);

  if (comparedWith?.has(object2)) {
    return true;
  }

  if (!comparedWith) {
    comparedWith = new WeakSet<object>();
    visited.set(object1, comparedWith);
  }

  comparedWith.add(object2);

  for (const key of keys1) {
    const val1 = object1[key];

    if (!(key in object2)) {
      return false;
    }

    if (key !== 'ref') {
      const val2 = object2[key];

